import React from 'react';
import { MultiStepForm } from './MultiStepForm';

export default function App() {
  const handleSubmit = (data: Record<string, string>) => {
    alert('Submitted: ' + JSON.stringify(data, null, 2));
  };

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Registration</h1>
      <MultiStepForm onSubmit={handleSubmit} />
    </div>
  );
}

import React, { useState } from 'react';
import './styles.css';

interface FormData {
  name: string;
  email: string;
  street: string;
  city: string;
}

interface MultiStepFormProps {
  onSubmit: (data: FormData) => void;
}

const TOTAL_STEPS = 3;

export const MultiStepForm: React.FC<MultiStepFormProps> = ({ onSubmit }) => {
  const [step, setStep] = useState(1);
  const [data, setData] = useState<FormData>({
    name: '',
    email: '',
    street: '',
    city: '',
  });

  // TODO: Implement per-step validation
  // TODO: Implement Next / Back navigation
  // TODO: Implement Submit on Step 3

  const updateField = (field: keyof FormData, value: string) => {
    setData((prev) => ({ ...prev, [field]: value }));
  };

  return (
    <div className="msf">
      <div data-testid="step-indicator" className="msf__indicator">
        Step {step} of {TOTAL_STEPS}
      </div>

      {/* Step 1: Personal */}
      {step === 1 && (
        <div className="msf__step">
          <label className="msf__label">
            Name
            <input
              data-testid="input-name"
              className="msf__input"
              value={data.name}
              onChange={(e) => updateField('name', e.target.value)}
              placeholder="Your name"
            />
          </label>
          <label className="msf__label">
            Email
            <input
              data-testid="input-email"
              className="msf__input"
              value={data.email}
              onChange={(e) => updateField('email', e.target.value)}
              placeholder="you@example.com"
            />
          </label>
        </div>
      )}

      {/* Step 2: Address */}
      {step === 2 && (
        <div className="msf__step">
          <label className="msf__label">
            Street
            <input
              data-testid="input-street"
              className="msf__input"
              value={data.street}
              onChange={(e) => updateField('street', e.target.value)}
              placeholder="123 Main St"
            />
          </label>
          <label className="msf__label">
            City
            <input
              data-testid="input-city"
              className="msf__input"
              value={data.city}
              onChange={(e) => updateField('city', e.target.value)}
              placeholder="Springfield"
            />
          </label>
        </div>
      )}

      {/* Step 3: Review */}
      {step === 3 && (
        <div className="msf__step msf__review">
          <p><strong>Name:</strong> <span data-testid="review-name">{data.name}</span></p>
          <p><strong>Email:</strong> <span data-testid="review-email">{data.email}</span></p>
          <p><strong>Street:</strong> <span data-testid="review-street">{data.street}</span></p>
          <p><strong>City:</strong> <span data-testid="review-city">{data.city}</span></p>
        </div>
      )}

      {/* Navigation */}
      <div className="msf__nav">
        <button data-testid="btn-back" className="msf__btn msf__btn--back" disabled>
          Back
        </button>
        {step < TOTAL_STEPS ? (
          <button data-testid="btn-next" className="msf__btn msf__btn--next">
            Next
          </button>
        ) : (
          <button data-testid="btn-submit" className="msf__btn msf__btn--submit">
            Submit
          </button>
        )}
      </div>
    </div>
  );
};

export default MultiStepForm;

.msf {
  max-width: 28rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  padding: 1.5rem;
  background: #ffffff;
}

.msf__indicator {
  font-size: 0.8125rem;
  font-weight: 600;
  color: #6b7280;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 1.25rem;
}

.msf__step {
  display: flex;
  flex-direction: column;
  gap: 1rem;
  margin-bottom: 1.5rem;
}

.msf__label {
  display: flex;
  flex-direction: column;
  gap: 0.375rem;
  font-size: 0.875rem;
  font-weight: 500;
  color: #374151;
}

.msf__input {
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  outline: none;
  transition: border-color 0.15s ease;
}

.msf__input:focus {
  border-color: #3b82f6;
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.15);
}

.msf__error {
  font-size: 0.75rem;
  color: #ef4444;
  margin-top: 0.125rem;
}

.msf__review {
  background: #f9fafb;
  border-radius: 0.375rem;
  padding: 1rem;
}

.msf__review p {
  margin: 0.375rem 0;
  font-size: 0.875rem;
  color: #374151;
}

.msf__nav {
  display: flex;
  justify-content: space-between;
  gap: 0.75rem;
}

.msf__btn {
  padding: 0.5rem 1.25rem;
  border-radius: 0.375rem;
  border: 1px solid #d1d5db;
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.15s ease;
}

.msf__btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.msf__btn--back {
  background: #f9fafb;
  color: #374151;
}

.msf__btn--back:hover:not(:disabled) {
  background: #f3f4f6;
}

.msf__btn--next {
  background: #3b82f6;
  color: white;
  border-color: #3b82f6;
  margin-left: auto;
}

.msf__btn--next:hover:not(:disabled) {
  background: #2563eb;
}

.msf__btn--submit {
  background: #10b981;
  color: white;
  border-color: #10b981;
  margin-left: auto;
}

.msf__btn--submit:hover:not(:disabled) {
  background: #059669;
}

