import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import { MultiStepForm } from './MultiStepForm';

describe('MultiStepForm', () => {
  const noop = () => {};

  it('starts on Step 1', () => {
    render(<MultiStepForm onSubmit={noop} />);
    expect(screen.getByTestId('step-indicator')).toHaveTextContent('Step 1 of 3');
    expect(screen.getByTestId('input-name')).toBeInTheDocument();
    expect(screen.getByTestId('input-email')).toBeInTheDocument();
  });

  it('disables Back on Step 1', () => {
    render(<MultiStepForm onSubmit={noop} />);
    expect(screen.getByTestId('btn-back')).toBeDisabled();
  });

  it('disables Next when Step 1 is invalid', () => {
    render(<MultiStepForm onSubmit={noop} />);
    expect(screen.getByTestId('btn-next')).toBeDisabled();
  });

  it('enables Next when Step 1 is valid', () => {
    render(<MultiStepForm onSubmit={noop} />);
    fireEvent.change(screen.getByTestId('input-name'), { target: { value: 'Jo' } });
    fireEvent.change(screen.getByTestId('input-email'), { target: { value: 'j@x.com' } });
    expect(screen.getByTestId('btn-next')).not.toBeDisabled();
  });

  it('navigates to Step 2 and shows address fields', () => {
    render(<MultiStepForm onSubmit={noop} />);
    fireEvent.change(screen.getByTestId('input-name'), { target: { value: 'Jo' } });
    fireEvent.change(screen.getByTestId('input-email'), { target: { value: 'j@x.com' } });
    fireEvent.click(screen.getByTestId('btn-next'));
    expect(screen.getByTestId('step-indicator')).toHaveTextContent('Step 2 of 3');
    expect(screen.getByTestId('input-street')).toBeInTheDocument();
    expect(screen.getByTestId('input-city')).toBeInTheDocument();
  });

  it('navigates back from Step 2 to Step 1 with data preserved', () => {
    render(<MultiStepForm onSubmit={noop} />);
    fireEvent.change(screen.getByTestId('input-name'), { target: { value: 'Jo' } });
    fireEvent.change(screen.getByTestId('input-email'), { target: { value: 'j@x.com' } });
    fireEvent.click(screen.getByTestId('btn-next'));
    fireEvent.click(screen.getByTestId('btn-back'));
    expect(screen.getByTestId('step-indicator')).toHaveTextContent('Step 1 of 3');
    expect(screen.getByTestId('input-name')).toHaveValue('Jo');
  });

  it('shows review on Step 3 with all entered data', () => {
    render(<MultiStepForm onSubmit={noop} />);
    fireEvent.change(screen.getByTestId('input-name'), { target: { value: 'Jo' } });
    fireEvent.change(screen.getByTestId('input-email'), { target: { value: 'j@x.com' } });
    fireEvent.click(screen.getByTestId('btn-next'));
    fireEvent.change(screen.getByTestId('input-street'), { target: { value: '1 Oak' } });
    fireEvent.change(screen.getByTestId('input-city'), { target: { value: 'NYC' } });
    fireEvent.click(screen.getByTestId('btn-next'));
    expect(screen.getByTestId('step-indicator')).toHaveTextContent('Step 3 of 3');
    expect(screen.getByTestId('review-name')).toHaveTextContent('Jo');
    expect(screen.getByTestId('review-email')).toHaveTextContent('j@x.com');
    expect(screen.getByTestId('review-street')).toHaveTextContent('1 Oak');
    expect(screen.getByTestId('review-city')).toHaveTextContent('NYC');
  });

  it('calls onSubmit with form data when Submit is clicked', () => {
    const spy = jest.fn();
    render(<MultiStepForm onSubmit={spy} />);
    fireEvent.change(screen.getByTestId('input-name'), { target: { value: 'Jo' } });
    fireEvent.change(screen.getByTestId('input-email'), { target: { value: 'j@x.com' } });
    fireEvent.click(screen.getByTestId('btn-next'));
    fireEvent.change(screen.getByTestId('input-street'), { target: { value: '1 Oak' } });
    fireEvent.change(screen.getByTestId('input-city'), { target: { value: 'NYC' } });
    fireEvent.click(screen.getByTestId('btn-next'));
    fireEvent.click(screen.getByTestId('btn-submit'));
    expect(spy).toHaveBeenCalledWith({
      name: 'Jo',
      email: 'j@x.com',
      street: '1 Oak',
      city: 'NYC',
    });
  });
});

