import React, { useState } from 'react';
import './styles.css';

interface FormData {
  name: string;
  email: string;
  street: string;
  city: string;
}

interface MultiStepFormProps {
  onSubmit: (data: FormData) => void;
}

const TOTAL_STEPS = 3;

const isStep1Valid = (d: FormData) => d.name.length >= 2 && d.email.includes('@');
const isStep2Valid = (d: FormData) => d.street.trim().length > 0 && d.city.trim().length > 0;

export const MultiStepForm: React.FC<MultiStepFormProps> = ({ onSubmit }) => {
  const [step, setStep] = useState(1);
  const [data, setData] = useState<FormData>({
    name: '',
    email: '',
    street: '',
    city: '',
  });

  const updateField = (field: keyof FormData, value: string) => {
    setData((prev) => ({ ...prev, [field]: value }));
  };

  const canGoNext =
    (step === 1 && isStep1Valid(data)) ||
    (step === 2 && isStep2Valid(data));

  const next = () => { if (canGoNext) setStep((s) => s + 1); };
  const back = () => setStep((s) => Math.max(1, s - 1));

  return (
    <div className="msf">
      <div data-testid="step-indicator" className="msf__indicator">
        Step {step} of {TOTAL_STEPS}
      </div>

      {step === 1 && (
        <div className="msf__step">
          <label className="msf__label">
            Name
            <input
              data-testid="input-name"
              className="msf__input"
              value={data.name}
              onChange={(e) => updateField('name', e.target.value)}
              placeholder="Your name"
            />
            {data.name.length > 0 && data.name.length < 2 && (
              <span className="msf__error">Name must be at least 2 characters</span>
            )}
          </label>
          <label className="msf__label">
            Email
            <input
              data-testid="input-email"
              className="msf__input"
              value={data.email}
              onChange={(e) => updateField('email', e.target.value)}
              placeholder="you@example.com"
            />
            {data.email.length > 0 && !data.email.includes('@') && (
              <span className="msf__error">Email must contain @</span>
            )}
          </label>
        </div>
      )}

      {step === 2 && (
        <div className="msf__step">
          <label className="msf__label">
            Street
            <input
              data-testid="input-street"
              className="msf__input"
              value={data.street}
              onChange={(e) => updateField('street', e.target.value)}
              placeholder="123 Main St"
            />
          </label>
          <label className="msf__label">
            City
            <input
              data-testid="input-city"
              className="msf__input"
              value={data.city}
              onChange={(e) => updateField('city', e.target.value)}
              placeholder="Springfield"
            />
          </label>
        </div>
      )}

      {step === 3 && (
        <div className="msf__step msf__review">
          <p><strong>Name:</strong> <span data-testid="review-name">{data.name}</span></p>
          <p><strong>Email:</strong> <span data-testid="review-email">{data.email}</span></p>
          <p><strong>Street:</strong> <span data-testid="review-street">{data.street}</span></p>
          <p><strong>City:</strong> <span data-testid="review-city">{data.city}</span></p>
        </div>
      )}

      <div className="msf__nav">
        <button
          data-testid="btn-back"
          className="msf__btn msf__btn--back"
          disabled={step === 1}
          onClick={back}
        >
          Back
        </button>
        {step < TOTAL_STEPS ? (
          <button
            data-testid="btn-next"
            className="msf__btn msf__btn--next"
            disabled={!canGoNext}
            onClick={next}
          >
            Next
          </button>
        ) : (
          <button
            data-testid="btn-submit"
            className="msf__btn msf__btn--submit"
            onClick={() => onSubmit(data)}
          >
            Submit
          </button>
        )}
      </div>
    </div>
  );
};

export default MultiStepForm;
